I've been wrestling with the oauth, oauthlib, and flask-oauthlib docs but still unclear where I set my session token name. Currently, I can only work with a session token named 'session' (a default I'm assuming) 

It seams strait-forward from the example that it should go into the flask session object e.g.

```python
from flask import session
# ...
session['name_token_whatever'] = 'token-contents'
```

But I've tried without luck. Below is my code.

```python
from flask import session, jsonify, redirect, url_for, request
from flask.ext.admin.contrib.sqla import ModelView
from flask.ext.wtf import Form
from app.extensions import oauth
from . import auth
import os
from uuid import uuid4


## Social auth
LINKEDIN_API_KEY = os.environ.get('LINKEDIN_API_KEY')
LINKEDIN_SECRET_KEY = os.environ.get('LINKEDIN_SECRET_KEY')

linkedin = oauth.remote_app(
  'linkedin',
  consumer_key=LINKEDIN_API_KEY,
  consumer_secret=LINKEDIN_SECRET_KEY,
  request_token_params={
      'scope': 'r_emailaddress',
      'state': lambda: uuid4()
    },
  base_url='https://api.linkedin.com/v1/',
  request_token_url=None,
  access_token_method='POST',
  access_token_url='https://www.linkedin.com/uas/oauth2/accessToken',
  authorize_url='https://www.linkedin.com/uas/oauth2/authorization',
)


@auth.route('/')
def index():
  if 'session' in session:
        me = linkedin.get('people/~')
        return jsonify(me.data)
  return redirect(url_for('auth.login'))


@auth.route('/login')
def login():
  return linkedin.authorize(callback=url_for('auth.authorized', _external=True))


@auth.route('/login/authorized')
def authorized():
  resp = linkedin.authorized_response()
  if resp is None:
    return 'Access denied: reason=%s error=%s' % (
      request.args['error_reason'],
      request.args['error_description']
    )
  session['session'] = (resp['access_token'], '')
  ## create user logic if none https://github.com/dstucrypt/sekininsha/blob/master/sekininsha/views.py
  me = linkedin.get('people/~:(id,num-connections,picture-url)')
  return jsonify(me.data)

@auth.route('/logout')
def logout():
    session.pop('session', None)
    return redirect(url_for('home'))

@linkedin.tokengetter
def get_linkedin_oauth2_token():
  return session.get('session')


def change_linkedin_query(uri, headers, body):
  li_auth = headers.pop('Authorization')
  headers['x-li-format'] = 'json'
  if li_auth:
    li_auth = li_auth.replace('Bearer', '').strip()
    if '?' in uri:
      uri += '&oauth2_access_token=' + li_auth
    else:
      uri += '?oauth2_access_token=' + li_auth
  return uri, headers, body

linkedin.pre_request = change_linkedin_query
```

